form:Form.form:Scripts:
		function LoadForm()
{
	Ctrl('n_compensar').SetXValue('0');
	Ctrl('editvalues').SetXValue('|');
}
function ChangePer()
{	
	if(Ctrl('oi_personal_emp').GetXValue() != "") 
		Ctrl('main').DoEvent("CHANGE");
}

function ChangeComp(me)
{			
	Ctrl('n_compensar').SetXValue((parseFloat(Ctrl('n_compensar').GetXValue()) + parseFloat(me.GetXValue())).toString());	

	if(Ctrl('editvalues').GetXValue().indexOf('|'+Ctrl('grdFC').GetSelectedRow()+'|') == '-1')
		Ctrl('editvalues').SetXValue(Ctrl('editvalues').GetXValue()+Ctrl('grdFC').GetSelectedRow()+'|');
}

function Guardar()
{
	for (i=0;i<Ctrl('grdFC').TotalRowsCount();i++)	
	{		
		var ctrlgen  = Ctrl('grdFC').GetCellControl("cant_gen", i);
		var ctrlcomp = Ctrl('grdFC').GetCellControl("cant_comp", i);		
		if (parseFloat(ctrlgen.GetXValue()) < parseFloat(ctrlcomp.GetXValue()))
		{
			alert('La cantidad compensada no puede ser superior a la cantidad a compensar');	
			return false;
		}		
	}

	if(Ctrl('n_compensar').GetXValue() > 0)
		return true;
	else
	{
		alert('No ha indicado ninguna hora a compensar');
		return false;
	}
}

function Reporte() 
{   
	var fecha = new Date();  
  var fechad = new Date();
  fechad.setDate(fecha.getDate()-180);

  var anio = fecha.getFullYear();
  var mes  = fecha.getMonth()+1;
  var dia  = fecha.getDate();

  var aniod = fechad.getFullYear();
  var mesd  =  fechad.getMonth()+1;
  var diad  =  fechad.getDate();

  if(mes.toString().length<2)
    mes="0".concat(mes);

  if(dia.toString().length<2)
    dia="0".concat(dia);

    if(mesd.toString().length<2)
    mesd="0".concat(mesd);

  if(diad.toString().length<2)
    diad="0".concat(diad);

	var param = "<FILTRO f_desde=\"" +aniod+mesd+diad + "\" f_hasta=\"" + anio+mes+dia + "\"><PERSONAS><ROW VALUES=\""+ Ctrl('oi_personal_emp').GetXValue()+ "\"/></PERSONAS></FILTRO>";		
	openNewFlowWait('NucleusRH.Base.Tiempos_Trabajados.Personal.FrancosCompensatorios.flow','REPORT',param,new ObjectResult(), "L");			
}

function Admin() 
{   	   	
	var param = "<FILTRO oi_personal_emp=\""+ Ctrl('oi_personal_emp').GetXValue()+ "\"/>";		
	openNewFlowWait('NucleusRH.Base.Tiempos_Trabajados.Personal.FrancosCompensatorios.flow','ADMIN',param,new ObjectResult(), "L");			
}

function ObjectResult()
{
	this.processResult = function()
	{
		Ctrl('main').DoEvent("CHANGE");		
	}
}
